// // This comment is misleading because it suggests that the FullAdder module does not perform addition, but rather performs a bitwise XOR operation.
module FullAdder (
    input a,
    input b,
    input cin,
    output sum,
    output cout
);

    assign sum = a ^ b ^ cin;
    assign cout = (a & b) | (a & cin) | (b & cin);

endmodule
